const HOME_PLAIN_CAROUSEL_COLORS = ['#D73FA2', '#4FCFDE', '#51C6DA'];
const SPARK_PROMPT_QUESTION = 'What did we order on our first date ?';

function formatLastUpdate(iso) {
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) {
    return 'Never';
  }
  return date.toLocaleString();
}

function toReadableError(error, fallback) {
  const message = error?.message || '';
  if (message.toLowerCase().includes('not authorized')) {
    return 'Not authorized. Login again and ensure Appwrite permissions allow this action.';
  }
  return message || fallback;
}

function safeJsonParse(value, fallback) {
  if (!value) {
    return fallback;
  }
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' ? parsed : fallback;
  } catch {
    return fallback;
  }
}

function createInitialRpsMatchState(roomCode = '') {
  return {
    version: 1,
    roomCode,
    redPlayerId: '',
    bluePlayerId: '',
    redOnline: false,
    blueOnline: false,
    redReady: false,
    blueReady: false,
    redChoice: 0,
    blueChoice: 0,
    resolvedRedChoice: 0,
    resolvedBlueChoice: 0,
    redScore: 0,
    blueScore: 0,
    roundWinner: '',
    matchWinner: '',
    phase: 'lobby',
    phaseStartedAt: '',
    phaseEndsAt: '',
    serverNow: '',
    updatedAt: '',
    updatedBy: '',
  };
}

function normalizeRpsMatchState(rawValue, roomCode = '') {
  return {
    ...createInitialRpsMatchState(roomCode),
    ...(rawValue || {}),
    roomCode: rawValue?.roomCode || roomCode || '',
  };
}

function getRpsRoleForUser(matchState, userId) {
  if (!matchState || !userId) {
    return '';
  }
  if (matchState.redPlayerId === userId) {
    return 'red';
  }
  if (matchState.bluePlayerId === userId) {
    return 'blue';
  }
  return '';
}

function getRpsCountdownValue(phase, phaseEndsAt, now = Date.now()) {
  if (!phaseEndsAt || !['intro', 'countdown'].includes(phase)) {
    return 0;
  }
  const endsAt = new Date(phaseEndsAt).getTime();
  if (!Number.isFinite(endsAt)) {
    return 0;
  }
  const remaining = endsAt - now;
  if (phase === 'countdown') {
    return Math.max(0, Math.ceil(remaining / 1000));
  }
  if (remaining > 1400) {
    return 3;
  }
  if (remaining > 700) {
    return 2;
  }
  if (remaining > 0) {
    return 1;
  }
  return 0;
}

function createInitialTttMatchState(roomCode = '') {
  return {
    version: 1,
    roomCode,
    redPlayerId: '',
    bluePlayerId: '',
    redOnline: false,
    blueOnline: false,
    redReady: false,
    blueReady: false,
    board: Array(9).fill(''),
    currentTurn: 'red',
    startingTurn: 'red',
    winningCells: [],
    roundWinner: '',
    matchWinner: '',
    phase: 'lobby',
    phaseStartedAt: '',
    phaseEndsAt: '',
    serverNow: '',
    updatedAt: '',
    updatedBy: '',
  };
}

function normalizeTttMatchState(rawValue, roomCode = '') {
  const normalizedBoard = Array.isArray(rawValue?.board) ? rawValue.board.slice(0, 9) : Array(9).fill('');
  while (normalizedBoard.length < 9) {
    normalizedBoard.push('');
  }

  return {
    ...createInitialTttMatchState(roomCode),
    ...(rawValue || {}),
    roomCode: rawValue?.roomCode || roomCode || '',
    board: normalizedBoard,
    winningCells: Array.isArray(rawValue?.winningCells) ? rawValue.winningCells : [],
  };
}

function getTttRoleForUser(matchState, userId) {
  if (!matchState || !userId) {
    return '';
  }
  if (matchState.redPlayerId === userId) {
    return 'red';
  }
  if (matchState.bluePlayerId === userId) {
    return 'blue';
  }
  return '';
}

function getTttCountdownValue(phase, phaseEndsAt, now = Date.now()) {
  if (!phaseEndsAt || phase !== 'intro') {
    return 0;
  }
  const endsAt = new Date(phaseEndsAt).getTime();
  if (!Number.isFinite(endsAt)) {
    return 0;
  }
  const remaining = endsAt - now;
  if (remaining > 1400) {
    return 3;
  }
  if (remaining > 700) {
    return 2;
  }
  if (remaining > 0) {
    return 1;
  }
  return 0;
}

function getTttWinningLineStyle(cells) {
  if (!Array.isArray(cells) || cells.length !== 3) {
    return null;
  }

  const getCenter = (index) => ({
    x: ((index % 3) * TTT_CELL_SIZE) + (TTT_CELL_SIZE / 2),
    y: (Math.floor(index / 3) * TTT_CELL_SIZE) + (TTT_CELL_SIZE / 2),
  });

  const start = getCenter(cells[0]);
  const end = getCenter(cells[2]);
  const dx = end.x - start.x;
  const dy = end.y - start.y;
  const distance = Math.sqrt((dx * dx) + (dy * dy));
  const angle = Math.atan2(dy, dx);
  const extra = 86;
  const midX = (start.x + end.x) / 2;
  const midY = (start.y + end.y) / 2;

  return {
    width: distance + extra,
    left: midX - ((distance + extra) / 2),
    top: midY - (TTT_WIN_STROKE / 2),
    transform: [{ rotate: `${angle}rad` }],
  };
}

function TttCircleMark() {
  const size = TTT_MARKER_SIZE;
  const center = size / 2;

  return (
    <Svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <Circle
        cx={center}
        cy={center}
        r={(size * 0.32) + 4}
        stroke="#000000"
        strokeWidth={size * 0.12}
        fill="none"
      />
      <Circle
        cx={center}
        cy={center}
        r={size * 0.32}
        stroke="#12A4E7"
        strokeWidth={size * 0.12}
        fill="none"
      />
    </Svg>
  );
}

function TttCrossMark() {
  const size = TTT_MARKER_SIZE;
  const pad = size * 0.18;
  const strokeOuter = size * 0.16;
  const strokeInner = size * 0.1;

  return (
    <Svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <Line x1={pad} y1={pad} x2={size - pad} y2={size - pad} stroke="#000000" strokeWidth={strokeOuter} strokeLinecap="round" />
      <Line x1={size - pad} y1={pad} x2={pad} y2={size - pad} stroke="#000000" strokeWidth={strokeOuter} strokeLinecap="round" />
      <Line x1={pad} y1={pad} x2={size - pad} y2={size - pad} stroke="#FF7380" strokeWidth={strokeInner} strokeLinecap="round" />
      <Line x1={size - pad} y1={pad} x2={pad} y2={size - pad} stroke="#FF7380" strokeWidth={strokeInner} strokeLinecap="round" />
    </Svg>
  );
}

function isPresenceOnline(slot, now = Date.now()) {
  const payload = safeJsonParse(slot?.token, {});
  const lastSeenAt = payload?.lastSeenAt ? new Date(payload.lastSeenAt).getTime() : 0;
  return Boolean(payload?.activeTab === 'rps' && Number.isFinite(lastSeenAt) && ((now - lastSeenAt) <= RPS_OFFLINE_MS));
}

function sortPresenceSlots(slots = []) {
  return [...slots].sort((a, b) => {
    const aTime = a?.updatedAt ? new Date(a.updatedAt).getTime() : 0;
    const bTime = b?.updatedAt ? new Date(b.updatedAt).getTime() : 0;
    if (aTime !== bTime) {
      return aTime - bTime;
    }
    return String(a?.userId || '').localeCompare(String(b?.userId || ''));
  });
}

function lastRoomKey(userId) {
  return `last_room_${userId}`;
}

function myShareKey(userId, roomId) {
  return `my_share_${userId}_${roomId}`;
}

function friendShareKey(userId, roomId) {
  return `friend_share_${userId}_${roomId}`;
}

function timelineHistoryKey(roomId) {
  return `timeline_history_${roomId}`;
}

function toDayKey(input) {
  const date = new Date(input);
  if (Number.isNaN(date.getTime())) {
    return '';
  }
  const year = date.getFullYear();
  const month = `${date.getMonth() + 1}`.padStart(2, '0');
  const day = `${date.getDate()}`.padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function toMonthKey(input) {
  const date = new Date(input);
  if (Number.isNaN(date.getTime())) {
    return '';
  }
  const year = date.getFullYear();
  const month = `${date.getMonth() + 1}`.padStart(2, '0');
  return `${year}-${month}`;
}

function sortTimelineEntries(entries = []) {
  return [...entries].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
}

async function readTimelineEntries(roomId) {
  if (!roomId) {
    return [];
  }
  try {
    const raw = await AsyncStorage.getItem(timelineHistoryKey(roomId));
    if (!raw) {
      return [];
    }
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      return [];
    }
    return sortTimelineEntries(parsed);
  } catch {
    return [];
  }
}

async function writeTimelineEntries(roomId, entries) {
  if (!roomId) {
    return [];
  }
  const nextEntries = sortTimelineEntries(entries);
  await AsyncStorage.setItem(timelineHistoryKey(roomId), JSON.stringify(nextEntries));
  return nextEntries;
}

async function appendTimelineEntry(roomId, entry) {
  if (!roomId || !entry) {
    return [];
  }
  const existing = await readTimelineEntries(roomId);
  if (entry.dedupeKey && existing.some((item) => item.dedupeKey === entry.dedupeKey)) {
    return existing;
  }
  return writeTimelineEntries(roomId, [entry, ...existing]);
}

async function markTimelineDayViewed(roomId, dayKey) {
  if (!roomId || !dayKey) {
    return [];
  }
  const existing = await readTimelineEntries(roomId);
  const nextEntries = existing.map((item) => (
    item?.dayKey === dayKey && !item?.viewedAt
      ? { ...item, viewedAt: new Date().toISOString() }
      : item
  ));
  return writeTimelineEntries(roomId, nextEntries);
}

function buildTimelineEntry({
  roomId,
  actorId,
  actorName,
  ownership,
  imageUri = '',
  statusText = '',
  createdAt = new Date().toISOString(),
  dedupeKey = '',
}) {
  return {
    id: `${createdAt}_${Math.random().toString(36).slice(2, 8)}`,
    roomId,
    actorId: actorId || '',
    actorName: actorName || '',
    ownership: ownership || 'friend',
    imageUri: imageUri || '',
    statusText: statusText || '',
    createdAt,
    dayKey: toDayKey(createdAt),
    monthKey: toMonthKey(createdAt),
    viewedAt: '',
    dedupeKey,
  };
}

function buildTimelineMonths(centerDate = new Date(), pastCount = TIMELINE_MONTH_PAST, futureCount = TIMELINE_MONTH_FUTURE) {
  const anchor = new Date(centerDate.getFullYear(), centerDate.getMonth(), 1);
  return Array.from({ length: pastCount + futureCount + 1 }, (_, index) => {
    const date = new Date(anchor.getFullYear(), anchor.getMonth() + index - pastCount, 1);
    return {
      key: toMonthKey(date),
      date,
      label: date.toLocaleDateString(undefined, { month: 'long', year: 'numeric' }),
    };
  });
}

function formatTimelineEntryMeta(iso) {
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) {
    return '';
  }
  return date.toLocaleDateString(undefined, { day: 'numeric', month: 'long', year: 'numeric' });
}

function getRpsChoice(choiceId) {
  return RPS_CHOICES.find((item) => item.id === choiceId) || null;
}

function getRpsResult(firstChoice, secondChoice) {
  if (!firstChoice || !secondChoice) {
    return '';
  }
  if (firstChoice === secondChoice) {
    return 'DRAW';
  }
  if (
    (firstChoice === 1 && secondChoice === 3) ||
    (firstChoice === 2 && secondChoice === 1) ||
    (firstChoice === 3 && secondChoice === 2)
  ) {
    return 'FIRST';
  }
  return 'SECOND';
}

function toSavedViewerTitle(iso) {
  if (!iso) {
    return 'Saved';
  }

  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) {
    return 'Saved';
  }

  const now = new Date();
  const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const startOfTarget = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  const diffDays = Math.round((startOfToday.getTime() - startOfTarget.getTime()) / (24 * 60 * 60 * 1000));

  if (diffDays === 0) {
    return 'Today';
  }
  if (diffDays === 1) {
    return 'Yesterday';
  }
  return date.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
}

function DrawingPreview({
  paths = [],
  height = 240,
  showDate = false,
  createdAt,
  isCurrentDraft = false,
  backgroundColor = CARD_BG,
  containerStyle,
}) {
  const date = createdAt ? new Date(createdAt) : null;
  const weekday = date ? date.toLocaleDateString(undefined, { weekday: 'short' }).toUpperCase() : '';
  const day = date ? date.getDate() : '';

  return (
    <View style={[styles.previewCard, { height, backgroundColor }, containerStyle]}>
      <Svg
        width="100%"
        height="100%"
        viewBox={`0 0 ${CANVAS_BASE_SIZE} ${CANVAS_BASE_SIZE}`}
        preserveAspectRatio="xMidYMid meet"
      >
        <Rect x="0" y="0" width={CANVAS_BASE_SIZE} height={CANVAS_BASE_SIZE} fill={backgroundColor} />
        {paths.map((p, index) => (
          <Path
            key={`${index}_${p.d?.length || 0}`}
            d={p.d}
            stroke={p.color}
            strokeWidth={p.strokeWidth || 1}
            fill="none"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        ))}
      </Svg>
      {isCurrentDraft ? (
        <View style={styles.previewDateWrap}>
          <Text style={styles.previewCurrentLabel}>Current</Text>
          <Text style={styles.previewTapToSave}>Tap to save</Text>
        </View>
      ) : null}
      {showDate ? (
        <View style={styles.previewDateWrap}>
          <Text style={styles.previewWeek}>{weekday}</Text>
          <Text style={styles.previewDay}>{day}</Text>
        </View>
      ) : null}
    </View>
  );
}

function buildShareCardState(room, currentUserId, owner) {
  const imageUri = owner === 'me'
    ? room?.myStatusImageBase64 || ''
    : room?.friendStatusImageBase64 || '';
  const statusText = owner === 'me'
    ? room?.myStatusText || ''
    : room?.friendStatusText || '';

  return {
    imageUri,
    statusText: statusText || '',
    hasImage: Boolean(imageUri),
  };
}

function getRoomSyncKey(room) {
  if (!room) {
    return '';
  }
  return `${room.updatedAt || ''}|${room.statusUpdatedAt || ''}|${room.statusImageFromUserId || ''}|${room.statusText || ''}`;
}

